class Solution:
    def reverseParentheses(self, s: str) -> str:
        stack, res = [], []
        for c in s:
            if c == '(':
                stack.append(res)
                res = []
            elif c == ')':
                tmp = res[::-1]
                res = stack.pop() + tmp
            else:
                res.append(c)
        return ''.join(res)
